import numpy as np
from scipy import ndimage

def solve(grid):
    grid = [list(row) for row in grid]
    H, W = len(grid), len(grid[0])
    g = np.array(grid)
    bg = int(g[0][0])

    mask = g != bg
    struct_arr = np.ones((3,3))
    labeled, num = ndimage.label(mask, structure=struct_arr)

    components = []
    for j in range(1, num+1):
        cells = np.argwhere(labeled == j)
        cells = [(int(r), int(c)) for r,c in cells]
        components.append(cells)

    sizes = [len(c) for c in components]
    min_size = min(sizes)
    small_comps = [c for c in components if len(c) == min_size]
    large_comps = [c for c in components if len(c) > min_size]

    def get_cross_center(cells_list):
        cell_colors = {(r,c): int(g[r,c]) for r,c in cells_list}
        non_frame = [(r,c) for r,c in cells_list if int(g[r,c]) != 1 and int(g[r,c]) != bg]
        if not non_frame:
            rows = [r for r,c in cells_list]
            cols = [c for r,c in cells_list]
            return (sum(rows)//len(rows), sum(cols)//len(cols))
        best = None
        best_count = -1
        for r,c in non_frame:
            count = 0
            for dr in [-1, 0, 1]:
                for dc in [-1, 0, 1]:
                    if dr == 0 and dc == 0: continue
                    if cell_colors.get((r+dr, c+dc)) == 1:
                        count += 1
            if count > best_count:
                best_count = count
                best = (r, c)
        return best

    def get_template(cells_list, center):
        cr, cc = center
        return {(r-cr, c-cc): int(g[r,c]) for r,c in cells_list}

    small_centers = []
    small_templates = []
    for comp in small_comps:
        center = get_cross_center(comp)
        template = get_template(comp, center)
        small_centers.append(center)
        small_templates.append(template)

    # Find two distinct templates
    distinct = []
    groups = []
    for i, t in enumerate(small_templates):
        found = False
        for j, d in enumerate(distinct):
            if t == d:
                groups[j].append(i)
                found = True
                break
        if not found:
            distinct.append(t)
            groups.append([i])

    t0, t1 = distinct[0], distinct[1]

    core = {}
    for pos in set(t0.keys()) & set(t1.keys()):
        if t0[pos] == t1[pos]:
            core[pos] = t0[pos]

    var0 = {pos: t0[pos] for pos in t0 if pos not in core}
    var1 = {pos: t1[pos] for pos in t1 if pos not in core}

    output = [row[:] for row in grid]

    # Swap small components
    for i, comp in enumerate(small_comps):
        cr, cc = small_centers[i]
        t = small_templates[i]

        if t == t0:
            remove, add = var0, var1
        else:
            remove, add = var1, var0

        for (dr, dc) in remove:
            r, c = cr + dr, cc + dc
            if 0 <= r < H and 0 <= c < W:
                output[r][c] = bg
        for (dr, dc), col in add.items():
            r, c = cr + dr, cc + dc
            if 0 <= r < H and 0 <= c < W:
                output[r][c] = col

    # Handle large components
    for comp in large_comps:
        large_center = get_cross_center(comp)
        lcr, lcc = large_center

        # Determine scale
        # Try scales 2-10 and match against both templates
        for scale in range(2, 11):
            for ti, (t_try, var_remove, var_add) in enumerate([(t0, var0, var1), (t1, var1, var0)]):
                # Check if template at this scale matches the large component
                match = True
                for (dr, dc), col in t_try.items():
                    for di in range(scale):
                        for dj in range(scale):
                            r = lcr + dr * scale + di
                            c = lcc + dc * scale + dj
                            if not (0 <= r < H and 0 <= c < W):
                                match = False
                                break
                            if int(g[r,c]) != col:
                                match = False
                                break
                        if not match:
                            break
                    if not match:
                        break

                if match:
                    # Verify the large component doesn't have extra cells
                    expected_cells = set()
                    for (dr, dc) in t_try:
                        for di in range(scale):
                            for dj in range(scale):
                                expected_cells.add((lcr + dr*scale + di, lcc + dc*scale + dj))
                    actual_cells = set((r,c) for r,c in comp)
                    if expected_cells == actual_cells:
                        # Apply swap
                        for (dr, dc) in var_remove:
                            for di in range(scale):
                                for dj in range(scale):
                                    r = lcr + dr*scale + di
                                    c = lcc + dc*scale + dj
                                    if 0 <= r < H and 0 <= c < W:
                                        output[r][c] = bg
                        for (dr, dc), col in var_add.items():
                            for di in range(scale):
                                for dj in range(scale):
                                    r = lcr + dr*scale + di
                                    c = lcc + dc*scale + dj
                                    if 0 <= r < H and 0 <= c < W:
                                        output[r][c] = col
                        break
                if match:
                    break
            if match:
                break

    return output

# Test
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    match = result == expected
    print(f"Training {i}: {'PASS' if match else 'FAIL'}")
    if not match:
        result_a = np.array(result)
        expected_a = np.array(expected)
        diff = np.where(result_a != expected_a)
        print(f"  {len(diff[0])} mismatches")

print("\nTest output:")
test_result = solve(test_samples[0]['input'])
# Show a summary
test_a = np.array(test_result)
test_i = np.array(test_samples[0]['input'])
diff = np.where(test_a != test_i)
print(f"Changed cells: {len(diff[0])}")
for r, c in zip(diff[0], diff[1]):
    print(f"  ({r},{c}): {int(test_i[r,c])} -> {int(test_a[r,c])}")

