import numpy as np
from scipy import ndimage

def solve(grid):
    grid = [list(row) for row in grid]
    H, W = len(grid), len(grid[0])
    g = np.array(grid)
    bg = int(g[0][0])

    mask = g != bg
    struct_arr = np.ones((3,3))
    labeled, num = ndimage.label(mask, structure=struct_arr)

    components = []
    for j in range(1, num+1):
        cells = np.argwhere(labeled == j)
        cells = [(int(r), int(c)) for r,c in cells]
        components.append(cells)

    sizes = [len(c) for c in components]
    min_size = min(sizes)
    small_comps = [c for c in components if len(c) == min_size]
    large_comps = [c for c in components if len(c) > min_size]

    def get_cross_center(cells_list):
        cell_colors = {(r,c): int(g[r,c]) for r,c in cells_list}
        non_frame = [(r,c) for r,c in cells_list if int(g[r,c]) != 1 and int(g[r,c]) != bg]
        if not non_frame:
            rows = [r for r,c in cells_list]
            cols = [c for r,c in cells_list]
            return (sum(rows)//len(rows), sum(cols)//len(cols))
        best = None
        best_count = -1
        for r,c in non_frame:
            count = 0
            for dr in [-1, 0, 1]:
                for dc in [-1, 0, 1]:
                    if dr == 0 and dc == 0: continue
                    if cell_colors.get((r+dr, c+dc)) == 1:
                        count += 1
            if count > best_count:
                best_count = count
                best = (r, c)
        return best

    def get_template(cells_list, center):
        cr, cc = center
        return {(r-cr, c-cc): int(g[r,c]) for r,c in cells_list}

    small_centers = []
    small_templates = []
    for comp in small_comps:
        center = get_cross_center(comp)
        template = get_template(comp, center)
        small_centers.append(center)
        small_templates.append(template)

    # Find two distinct templates
    distinct = []
    groups = []
    for i, t in enumerate(small_templates):
        found = False
        for j, d in enumerate(distinct):
            if t == d:
                groups[j].append(i)
                found = True
                break
        if not found:
            distinct.append(t)
            groups.append([i])

    t0, t1 = distinct[0], distinct[1]

    core = {}
    for pos in set(t0.keys()) & set(t1.keys()):
        if t0[pos] == t1[pos]:
            core[pos] = t0[pos]

    var0 = {pos: t0[pos] for pos in t0 if pos not in core}
    var1 = {pos: t1[pos] for pos in t1 if pos not in core}

    output = [row[:] for row in grid]

    # Swap small components
    for i, comp in enumerate(small_comps):
        cr, cc = small_centers[i]
        t = small_templates[i]

        if t == t0:
            remove, add = var0, var1
        else:
            remove, add = var1, var0

        for (dr, dc) in remove:
            r, c = cr + dr, cc + dc
            if 0 <= r < H and 0 <= c < W:
                output[r][c] = bg
        for (dr, dc), col in add.items():
            r, c = cr + dr, cc + dc
            if 0 <= r < H and 0 <= c < W:
                output[r][c] = col

    # Handle large components
    for comp in large_comps:
        large_center = get_cross_center(comp)
        lcr, lcc = large_center

        # Determine scale
        # Try scales 2-10 and match against both templates
        for scale in range(2, 11):
