                # Check if template at this scale matches the large component
                match = True
                for (dr, dc), col in t_try.items():
                    for di in range(scale):
                        for dj in range(scale):
                            r = lcr + dr * scale + di
                            c = lcc + dc * scale + dj
                            if not (0 <= r < H and 0 <= c < W):
                                match = False
                                break
                            if int(g[r,c]) != col:
                                match = False
                                break
                        if not match:
                            break
                    if not match:
                        break

                if match:
                    # Verify the large component doesn't have extra cells
                    expected_cells = set()
                    for (dr, dc) in t_try:
                        for di in range(scale):
                            for dj in range(scale):
                                expected_cells.add((lcr + dr*scale + di, lcc + dc*scale + dj))
                    actual_cells = set((r,c) for r,c in comp)
                    if expected_cells == actual_cells:
                        # Apply swap
                        for (dr, dc) in var_remove:
                            for di in range(scale):
                                for dj in range(scale):
                                    r = lcr + dr*scale + di
                                    c = lcc + dc*scale + dj
                                    if 0 <= r < H and 0 <= c < W:
                                        output[r][c] = bg
                        for (dr, dc), col in var_add.items():
                            for di in range(scale):
                                for dj in range(scale):
                                    r = lcr + dr*scale + di
                                    c = lcc + dc*scale + dj
                                    if 0 <= r < H and 0 <= c < W:
                                        output[r][c] = col
                        break
                if match:
                    break
            if match:
                break

    return output

